import React, { createContext, useContext, useEffect, useMemo, useReducer } from 'react';
import { View, Text, TextInput, TouchableOpacity, ActivityIndicator, StyleSheet, SafeAreaView } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AUTH_STORAGE_KEY = '@mvp_auth';

const fakeApi = {
  login: async ({ email, password }) => {
    await new Promise(resolve => setTimeout(resolve, 1000));
    if (!email || !password) {
      throw new Error('Email and password are required');
    }
    return {
      token: 'token_' + Date.now(),
      user: {
        id: '1',
        name: 'MVP User',
        email,
      },
    };
  },
  register: async ({ name, email, password }) => {
    await new Promise(resolve => setTimeout(resolve, 1000));
    if (!name || !email || !password) {
      throw new Error('All fields are required');
    }
    return {
      token: 'token_' + Date.now(),
      user: {
        id: '1',
        name,
        email,
      },
    };
  },
};

const AuthContext = createContext(null);

const initialState = {
  isLoading: true,
  token: null,
  user: null,
  error: null,
};

function authReducer(state, action) {
  switch (action.type) {
    case 'RESTORE_START':
      return { ...state, isLoading: true, error: null };
    case 'RESTORE_SUCCESS':
      return {
        ...state,
        isLoading: false,
        token: action.payload.token,
        user: action.payload.user,
        error: null,
      };
    case 'AUTH_SUCCESS':
      return {
        ...state,
        isLoading: false,
        token: action.payload.token,
        user: action.payload.user,
        error: null,
      };
    case 'AUTH_ERROR':
      return {
        ...state,
        isLoading: false,
        error: action.payload,
      };
    case 'SIGN_OUT':
      return {
        ...state,
        isLoading: false,
        token: null,
        user: null,
        error: null,
      };
    default:
      return state;
  }
}

async function saveAuthSession(session) {
  await AsyncStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(session));
}

async function loadAuthSession() {
  const raw = await AsyncStorage.getItem(AUTH_STORAGE_KEY);
  return raw ? JSON.parse(raw) : null;
}

async function clearAuthSession() {
  await AsyncStorage.removeItem(AUTH_STORAGE_KEY);
}

export function AuthProvider({ children }) {
  const [state, dispatch] = useReducer(authReducer, initialState);

  useEffect(() => {
    let mounted = true;

    const restoreSession = async () => {
      dispatch({ type: 'RESTORE_START' });
      try {
        const session = await loadAuthSession();
        if (!mounted) return;

        if (session?.token && session?.user) {
          dispatch({
            type: 'RESTORE_SUCCESS',
            payload: {
              token: session.token,
              user: session.user,
            },
          });
        } else {
          dispatch({
            type: 'RESTORE_SUCCESS',
            payload: {
              token: null,
              user: null,
            },
          });
        }
      } catch (e) {
        if (!mounted) return;
        dispatch({
          type: 'RESTORE_SUCCESS',
          payload: {
            token: null,
            user: null,
          },
        });
      }
    };

    restoreSession();

    return () => {
      mounted = false;
    };
  }, []);

  const auth = useMemo(
    () => ({
      ...state,
      isAuthenticated: !!state.token,
      signIn: async ({ email, password }) => {
        dispatch({ type: 'RESTORE_START' });
        try {
          const result = await fakeApi.login({ email, password });
          await saveAuthSession(result);
          dispatch({ type: 'AUTH_SUCCESS', payload: result });
        } catch (e) {
          dispatch({ type: 'AUTH_ERROR', payload: e.message || 'Login failed' });
        }
      },
      signUp: async ({ name, email, password }) => {
        dispatch({ type: 'RESTORE_START' });
        try {
          const result = await fakeApi.register({ name, email, password });
          await saveAuthSession(result);
          dispatch({ type: 'AUTH_SUCCESS', payload: result });
        } catch (e) {
          dispatch({ type: 'AUTH_ERROR', payload: e.message || 'Registration failed' });
        }
      },
      signOut: async () => {
        await clearAuthSession();
        dispatch({ type: 'SIGN_OUT' });
      },
      updateSession: async payload => {
        const nextSession = {
          token: payload.token ?? state.token,
          user: payload.user ?? state.user,
        };
        await saveAuthSession(nextSession);
        dispatch({ type: 'AUTH_SUCCESS', payload: nextSession });
      },
      clearError: () => dispatch({ type: 'AUTH_ERROR', payload: null }),
    }),
    [state]
  );

  return <AuthContext.Provider value={auth}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
}

function LoadingScreen() {
  return (
    <SafeAreaView style={styles.centered}>
      <ActivityIndicator size="large" />
      <Text style={styles.subtitle}>Restoring session...</Text>
    </SafeAreaView>
  );
}

function AuthScreen() {
  const { signIn, signUp, isLoading, error, clearError } = useAuth();
  const [mode, setMode] = React.useState('login');
  const [name, setName] = React.useState('');
  const [email, setEmail] = React.useState('');
  const [password, setPassword] = React.useState('');

  const submit = async () => {
    clearError();
    if (mode === 'login') {
      await signIn({ email, password });
    } else {
      await signUp({ name, email, password });
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>{mode === 'login' ? 'Sign In' : 'Create Account'}</Text>

        {mode === 'register' && (
          <TextInput
            placeholder="Name"
            value={name}
            onChangeText={setName}
            style={styles.input}
            autoCapitalize="words"
          />
        )}

        <TextInput
          placeholder="Email"
          value={email}
          onChangeText={text => {
            if (error) clearError();
            setEmail(text);
          }}
          style={styles.input}
          autoCapitalize="none"
          keyboardType="email-address"
        />

        <TextInput
          placeholder="Password"
          value={password}
          onChangeText={text => {
            if (error) clearError();
            setPassword(text);
          }}
          style={styles.input}
          secureTextEntry
        />

        {error ? <Text style={styles.error}>{error}</Text> : null}

        <TouchableOpacity style={styles.button} onPress={submit} disabled={isLoading}>
          {isLoading ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.buttonText}>{mode === 'login' ? 'Login' : 'Register'}</Text>
          )}
        </TouchableOpacity>

        <TouchableOpacity
          onPress={() => {
            clearError();
            setMode(mode === 'login' ? 'register' : 'login');
          }}
        >
          <Text style={styles.switchText}>
            {mode === 'login' ? "Don't have an account? Register" : 'Already have an account? Login'}
          </Text>
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const { user, token, signOut } = useAuth();

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Welcome</Text>
        <Text style={styles.subtitle}>{user?.name}</Text>
        <Text style={styles.meta}>{user?.email}</Text>
        <Text style={styles.tokenLabel}>Token</Text>
        <Text style={styles.tokenValue}>{token}</Text>

        <TouchableOpacity style={[styles.button, styles.logoutButton]} onPress={signOut}>
          <Text style={styles.buttonText}>Logout</Text>
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
}

function AuthGate() {
  const { isLoading, isAuthenticated } = useAuth();

  if (isLoading) {
    return <LoadingScreen />;
  }

  return isAuthenticated ? <HomeScreen /> : <AuthScreen />;
}

export default function App() {
  return (
    <AuthProvider>
      <AuthGate />
    </AuthProvider>
  );
}

